# frozen_string_literal: true

require 'swagger_helper'

# rubocop:disable RSpec/EmptyExampleGroup, RSpec/VariableName
RSpec.describe 'Admin Users API', type: :request do
  let(:admin) { create(:auth_credential, :admin) }
  let(:Authorization) { "Bearer #{JWTService.generate_access_token(admin)}" }

  # ===========================================================================
  # GET /api/v1/admin/users
  # ===========================================================================

  path '/api/v1/admin/users' do
    get 'List users (paginated)' do
      tags 'Admin - Users'
      security [bearer_auth: []]
      produces 'application/json'

      parameter name: :page, in: :query, type: :integer, required: false,
                description: 'Page number (default: 1)', example: 1
      parameter name: :per_page, in: :query, type: :integer, required: false,
                description: 'Results per page, 1-100 (default: 25)', example: 25
      parameter name: :search, in: :query, type: :string, required: false,
                description: 'Filter users by email (case-insensitive substring match)', example: 'admin'

      response '200', 'Users listed' do
        schema type: :object,
               properties: {
                 users: {
                   type: :array,
                   items: { '$ref' => '#/components/schemas/admin_user' }
                 },
                 meta: {
                   type: :object,
                   properties: {
                     total: { type: :integer },
                     page: { type: :integer },
                     per_page: { type: :integer }
                   },
                   required: %w[total page per_page]
                 }
               }

        before { create_list(:auth_credential, 2) }

        run_test!
      end

      response '200', 'Users filtered by email search' do
        schema type: :object,
               properties: {
                 users: {
                   type: :array,
                   items: { '$ref' => '#/components/schemas/admin_user' }
                 },
                 meta: {
                   type: :object,
                   properties: {
                     total: { type: :integer },
                     page: { type: :integer },
                     per_page: { type: :integer }
                   },
                   required: %w[total page per_page]
                 }
               }

        let!(:alice) { create(:auth_credential, email: 'alice@example.com') }
        let!(:bob)   { create(:auth_credential, email: 'bob@example.com') }
        let(:search) { 'alice' }

        run_test! do |response|
          data = JSON.parse(response.body)
          expect(data['users'].pluck('email')).to contain_exactly('alice@example.com')
          expect(data['meta']['total']).to eq(1)
        end
      end

      response '200', 'Search with no matching users returns empty list' do
        schema type: :object,
               properties: {
                 users: { type: :array, items: { '$ref' => '#/components/schemas/admin_user' } },
                 meta: {
                   type: :object,
                   properties: {
                     total: { type: :integer },
                     page: { type: :integer },
                     per_page: { type: :integer }
                   },
                   required: %w[total page per_page]
                 }
               }

        let(:search) { 'zzznomatch' }

        run_test! do |response|
          data = JSON.parse(response.body)
          expect(data['users']).to be_empty
          expect(data['meta']['total']).to eq(0)
        end
      end

      response '200', 'Search is case-insensitive' do
        schema type: :object,
               properties: {
                 users: { type: :array, items: { '$ref' => '#/components/schemas/admin_user' } },
                 meta: {
                   type: :object,
                   properties: {
                     total: { type: :integer },
                     page: { type: :integer },
                     per_page: { type: :integer }
                   },
                   required: %w[total page per_page]
                 }
               }

        let!(:alice) { create(:auth_credential, email: 'alice@example.com') }
        let(:search) { 'ALICE' }

        run_test! do |response|
          data = JSON.parse(response.body)
          expect(data['users'].pluck('email')).to include('alice@example.com')
        end
      end

      response '401', 'Missing or invalid token' do
        schema '$ref' => '#/components/schemas/error'

        let(:Authorization) { nil }
        run_test!
      end

      response '403', 'Not an admin' do
        schema '$ref' => '#/components/schemas/error'

        let(:regular_user) { create(:auth_credential) }
        let(:Authorization) { "Bearer #{JWTService.generate_access_token(regular_user)}" }
        run_test!
      end
    end
  end

  # ===========================================================================
  # GET /api/v1/admin/users/:id
  # ===========================================================================

  path '/api/v1/admin/users/{id}' do
    parameter name: :id, in: :path, type: :string, format: :uuid

    get 'Get a user' do
      tags 'Admin - Users'
      security [bearer_auth: []]
      produces 'application/json'

      response '200', 'User found' do
        schema type: :object,
               properties: {
                 user: { '$ref' => '#/components/schemas/admin_user' }
               }

        let(:target) { create(:auth_credential) }
        let(:id) { target.id }
        run_test!
      end

      response '404', 'User not found' do
        schema '$ref' => '#/components/schemas/error'

        let(:id) { '00000000-0000-0000-0000-000000000000' }
        run_test!
      end
    end
  end

  # ===========================================================================
  # PATCH /api/v1/admin/users/:id/deactivate
  # ===========================================================================

  path '/api/v1/admin/users/{id}/deactivate' do
    parameter name: :id, in: :path, type: :string, format: :uuid

    patch 'Deactivate a user' do
      tags 'Admin - Users'
      security [bearer_auth: []]
      produces 'application/json'

      response '200', 'User deactivated' do
        schema type: :object,
               properties: {
                 message: { type: :string },
                 user: { '$ref' => '#/components/schemas/admin_user' }
               }

        let(:target) { create(:auth_credential) }
        let(:id) { target.id }
        run_test!
      end

      response '422', 'Already deactivated or self-deactivation' do
        schema '$ref' => '#/components/schemas/error'

        let(:id) { admin.id }
        run_test!
      end

      response '404', 'User not found' do
        schema '$ref' => '#/components/schemas/error'

        let(:id) { '00000000-0000-0000-0000-000000000000' }
        run_test!
      end
    end
  end

  # ===========================================================================
  # PATCH /api/v1/admin/users/:id/activate
  # ===========================================================================

  path '/api/v1/admin/users/{id}/activate' do
    parameter name: :id, in: :path, type: :string, format: :uuid

    patch 'Activate a user' do
      tags 'Admin - Users'
      security [bearer_auth: []]
      produces 'application/json'

      response '200', 'User activated' do
        schema type: :object,
               properties: {
                 message: { type: :string },
                 user: { '$ref' => '#/components/schemas/admin_user' }
               }

        let(:target) { create(:auth_credential, :deactivated) }
        let(:id) { target.id }
        run_test!
      end

      response '422', 'User is already active' do
        schema '$ref' => '#/components/schemas/error'

        let(:target) { create(:auth_credential) }
        let(:id) { target.id }
        run_test!
      end
    end
  end
end
